import React from "react";

function InflationLoss(){

return(

<div>

<h2>Inflation Loss Analysis</h2>

<p>
Due to market inflation the cost of vegetables,
transport and raw materials increased which
reduced the profit margin.
</p>

<ul>

<li>Vegetable price rise : ₹900</li>
<li>Transport cost increase : ₹600</li>
<li>Packaging price rise : ₹300</li>

</ul>

</div>

)

}

export default InflationLoss;
